async function main() {
  console.log(`Starting batch 13 SEO rewrite for ${updates.length} products...\n`);

  let successCount = 0;
  let errorCount = 0;

  for (const update of updates) {
    try {
      const descWords = update.description.split(/\s+/).length;
      const metaLen = update.metaDescription.length;

      if (descWords < 250) {
        console.log(`⚠️  SKIP ${update.slug}: description only ${descWords} words (need 250+)`);
        errorCount++;
        continue;
      }
      if (metaLen < 130 || metaLen > 155) {
        console.log(`⚠️  SKIP ${update.slug}: meta description ${metaLen} chars (need 130-155)`);
        errorCount++;
        continue;
      }

      const result = await prisma.product.update({
        where: { slug: update.slug },
        data: {
          description: update.description,
          metaDescription: update.metaDescription,
        },
      });

      successCount++;
      console.log(`✅ ${update.slug} — desc: ${descWords} words, meta: ${metaLen} chars`);
    } catch (err) {
      errorCount++;
      console.log(`❌ ${update.slug} — ERROR: ${err.message}`);
    }
  }

  console.log(`\nDone: ${successCount} updated, ${errorCount} errors`);
}

main()
  .catch(console.error)
  .finally(() => prisma.$disconnect());
